mapper.select:

WHERE TRUNC(STARTDATE) <= #{date}
AND TRUNC(ENDDATE)   >= #{date}


    AND DISTRICT = #{district}



    AND (
    LOWER(CULUTENAME)        LIKE '%' || LOWER(#{q}) || '%'
    OR LOWER(DESCRIPTION)       LIKE '%' || LOWER(#{q}) || '%'
    OR LOWER(ORGANIZATIONNAME)  LIKE '%' || LOWER(#{q}) || '%'
    )


ORDER BY STARTDATE DESC NULLS LAST, CULUTENAME
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

SELECT COUNT(1)
FROM (

WHERE TRUNC(STARTDATE) <= #{date}
AND TRUNC(ENDDATE)   >= #{date}


    AND DISTRICT = #{district}



    AND (
    LOWER(CULUTENAME)        LIKE '%' || LOWER(#{q}) || '%'
    OR LOWER(DESCRIPTION)       LIKE '%' || LOWER(#{q}) || '%'
    OR LOWER(ORGANIZATIONNAME)  LIKE '%' || LOWER(#{q}) || '%'
    )

)


WHERE TRUNC(ENDDATE)   >= #{from}
AND TRUNC(STARTDATE) <= #{to}


    AND DISTRICT = #{district}


ORDER BY STARTDATE
FETCH FIRST #{limit} ROWS ONLY


WHERE TRUNC(ENDDATE)   >= #{from}
AND TRUNC(STARTDATE) <= #{to}


    AND DISTRICT = #{district}



    AND (
    LOWER(CULUTENAME)        LIKE '%' || LOWER(#{q}) || '%'
    OR LOWER(DESCRIPTION)       LIKE '%' || LOWER(#{q}) || '%'
    OR LOWER(ORGANIZATIONNAME)  LIKE '%' || LOWER(#{q}) || '%'
    )

ORDER BY STARTDATE
